        var q = parseJSON(resp.body);
        if (!q.token) return { ok: true, message: q.msg || "动画疯今日无可答题目或已答题" };
        return ctx.http.get(ctx.env, "https://api.gamer.com.tw/mobile_app/bahamut/v1/home.php?owner=blackXblue&page=1", ctx.headers(ctx.getCookie()), 1)
