            var article = parseJSON(articleResp.body);
            var today = (new Date().getMonth() + 1).toString().padStart(2, "0") + "/" + new Date().getDate().toString().padStart(2, "0");
            var list = (article.creation || []).filter(function(x) { return x.title && x.title.indexOf(today) >= 0; });
